export class FileUploadContext {
    isDragging = $state(false);
    inputRef = $state<HTMLInputElement | null>(null);
    multiple = $state<boolean>(true);
    disabled = $state<boolean>(false);

    constructor(multiple: boolean = true, disabled: boolean = false) {
        this.multiple = multiple;
        this.disabled = disabled;
    }
}

import FileUpload from "./file-upload.svelte";
import FileUploadContent from "./file-upload-content.svelte";
import FileUploadTrigger from "./file-upload-trigger.svelte";
import { FileUploadContext } from "./context.svelte";

export {
    FileUpload,
    FileUploadContent,
    FileUploadTrigger,
    FileUploadContext,
    //
    FileUpload as Root,
    FileUploadContent as Content,
    FileUploadTrigger as Trigger,
};
